const data = $input.first().json.body;

if (!data.alumnos || !Array.isArray(data.alumnos) || data.alumnos.length === 0) {
  return [{ json: {
    status: 'error',
    mensaje: 'Campo obligatorio: alumnos (array de nombres)'
  } }];
}

const numGrupos = data.num_grupos || 2;

if (numGrupos < 2) {
  return [{ json: { status: 'error', mensaje: 'num_grupos debe ser al menos 2' } }];
}
if (numGrupos > data.alumnos.length) {
  return [{ json: { status: 'error', mensaje: `No se pueden crear ${numGrupos} grupos con solo ${data.alumnos.length} alumnos` } }];
}

// Fisher-Yates shuffle: algoritmo estandar para mezcla aleatoria uniforme
const alumnos = [...data.alumnos];
for (let i = alumnos.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [alumnos[i], alumnos[j]] = [alumnos[j], alumnos[i]];
}

// Distribucion round-robin para equilibrar los grupos
const grupos = [];
for (let i = 0; i < numGrupos; i++) {
  grupos.push({ nombre: `Grupo ${i + 1}`, miembros: [] });
}
alumnos.forEach((alumno, index) => {
  grupos[index % numGrupos].miembros.push(alumno);
});

// Anadir conteo a cada grupo
grupos.forEach(g => g.total = g.miembros.length);

return [{ json: {
  status: 'ok',
  total_alumnos: data.alumnos.length,
  num_grupos: numGrupos,
  grupos,
  fecha: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' }),
  nota: 'Cada ejecucion genera una distribucion diferente'
} }];
